You can filter out `Can't Tell` outcomes before processing results ‚Äî here's a clean pattern for CI-compatible reports:

```ts
import { Playwright, Audit } from '@siteimprove/alfa-playwright';
import { Page } from '@playwright/test';

interface AuditSummary {
  passed: number;
  failed: number;
  inapplicable: number;
  canTellsCount: number;
}

async function runAccessibleAudit(page: Page): Promise<AuditSummary> {
  const alfaPage = Playwright.toPage(page);
  const results = await Audit.run(alfaPage);

  const summary: AuditSummary = {
    passed: 0,
    failed: 0,
    inapplicable: 0,
    canTellsCount: 0
  };

  for await (const result of results) {
    switch (result.outcome) {
      case 'Passed':
        summary.passed += 1;
        break;
      case 'Failed':
        summary.failed += 1;
        break;
      case 'Inapplicable':
        summary.inapplicable += 1;
        break;
      case "Can't Tell":
        summary.canTellsCount += 1;
        break;
    }
  }

  return summary;
}

// In CI: fail only on failures, not can't tells
if (summary.failed > 0) {
  console.error(`‚ùå ${summary.failed} accessibility failures found`);
  process.exit(1);
} else {
  console.log(`‚úÖ ${summary.passed} checks passed. ${summary.canTellsCount} manual review items (not blocking).`);
}
```

