  const alfaResults = await Audit.run(alfaPage);

  // 3. Restore snapshot to original state (to avoid mutation artifacts)
  await page.setContent(snapshot);

  // 4. Run axe (via browser context)
  const axeResults = await page.evaluate(() => axe.run());

  // 5. Compare failures
  const alfaFailures = alfaResults.filter(r => r.outcome === 'Failed').map(r => r.identifier);
  const axeFailures = axeResults.violations.map(v => v.id);

