```ts
import { Audit } from '@siteimprove/alfa-test-utils';
import { Playwright } from '@siteimprove/alfa-playwright';
import { Page } from '@playwright/test';

export async function getFailedRelevantRules(page: Page) {
  const documentHandle = await page.evaluateHandle(() => document);
  const alfaPage = Playwright.toPage(documentHandle);
  const results = await Audit.run(alfaPage);

  const targets = ['1.4.1', '1.4.3', '4.1.2'];

  const failedRelevant = results
    .filter(r => r.outcome === 'Failed')
    .filter(r => targets.includes(r.id)); // Alfa rule IDs follow WCAG SC format

  return failedRelevant.map(r => ({
    id: r.id,
    description: r.description.toString(),
    targets: r.target.map(t => t.toString()).join(', '),
    help: r.help.toString()
  }));
}
```

Notes:
- Alfa rule IDs match WCAG SC numbers (e.g., `'1.4.3'`)
- `r.target` is an array of `Node` ‚Äî convert via `.toString()` for reporting
- Use `r.help.toString()` for an actionable fix ‚Äî it‚Äôs part of the spec
- For CI, fail the build if `failedRelevant.length > 0`

