Here‚Äôs a robust TypeScript pattern to filter and categorize Alfa audit results:

```ts
import { Audit, Playwright } from '@siteimprove/alfa-playwright';
import type { AuditResult } from '@siteimprove/alfa-act';

export interface ResultBreakdown {
  failed: AuditResult[];
  cantTell: AuditResult[];
  passed: AuditResult[];
  inapplicable: AuditResult[];
}

export function breakdownResults(results: AuditResult[]): ResultBreakdown {
  const failed: AuditResult[] = [];
  const cantTell: AuditResult[] = [];
  const passed: AuditResult[] = [];
  const inapplicable: AuditResult[] = [];

  for (const result of results) {
    switch (result.outcome) {
      case 'Failed':
        failed.push(result);
        break;
      case "Can't Tell":
        cantTell.push(result);
        break;
      case 'Passed':
        passed.push(result);
        break;
      case 'Inapplicable':
        inapplicable.push(result);
        break;
    }
  }

  return { failed, cantTell, passed, inapplicable };
}

// Usage in Playwright test:
test('audit with breakdown', async ({ page }) => {
  await page.goto('https://agency.example.org');
  const alfaPage = Playwright.toPage(page);
  const results = await Audit.run(alfaPage);
  const { failed, cantTell } = breakdownResults(results);

  // Log counts
  console.log(`Failed: ${failed.length}`);
  console.log(`Can't Tell (manual review): ${cantTell.length}`);

  // Fail only on explicit failures (not Can't Tell)
  expect(failed, 'No failed rules').toStrictEqual([]);
});
```

